def check_number(num):
    if num > 0:
        return 'Positive'
    else:
        if num < 0:
            return 'Negative'
        else:
            return 'Zero'

def classify_age(age):
    if age < 13:
        return 'Child'
    else:
        if age < 20:
            return 'Teenager'
        else:
            return 'Adult'

def assign_grade(score):
    if score >= 90:
        return 'A'
    else:
        if score >= 80:
            return 'B'
        elif score >= 70:
            return 'C'
        elif score >= 60:
            return 'D'
        else:
            return 'F'
